# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.postcondition","kind":"function","src_hash":"7fbae065e519753f","in":{"base":"Union[str, Callable]","pred":"isinstance(predicate_or_func, str)"},"out":{"base":"Any"},"spec":{"lhs":"postcondition(pre)","rhs":"mark a postcondition","over":{"base":"Union[str, Callable]","pred":"isinstance(predicate_or_func, str)"},"name":"postcondition_correct"},"guarantee":"mark a postcondition","fibers":[{"name":"str","pred":"isinstance(predicate_or_func, str)","path":{"lhs":"postcondition(x)","rhs":"mark a postcondition","over":{"base":"str","pred":"isinstance(predicate_or_func, str)"},"name":"postcondition_str_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.postcondition_str_correct","statement":"postcondition satisfies spec on str inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"efba2eafb8b63a40"}
def postcondition(predicate_or_func: Union[str, Callable]) -> Any:
    """Mark a postcondition.

    As decorator: ``@postcondition("sorted(result)")``
    As statement: ``postcondition("len(result) == len(input)")``

    When used as a decorator, attaches postcondition metadata to the function.
    When used as a statement (string arg) inside a function body, returns True.
    """
    if callable(predicate_or_func) and not isinstance(predicate_or_func, str):
        # Used as @postcondition without arguments (unusual)
        return predicate_or_func

    predicate = predicate_or_func

    def decorator(func: Callable) -> Callable:
        if not hasattr(func, '__postconditions__'):
            func.__postconditions__ = []
        func.__postconditions__.append(predicate)
        return func

    # Always return the decorator — if called as a statement in a function
    # body, the returned decorator object is truthy (which is fine).
    # The AST parser handles the marker extraction separately.
    return decorator


