        if self.assumed_steps:
            parts.append(f'{self.assumed_steps} assumed')
        if self.unverified_steps:
            parts.append(f'{self.unverified_steps} unverified')
        return f'[{self.max_trust.value}] {", ".join(parts) or "empty"}'


