# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_z3","kind":"function","src_hash":"04c4186bc54396f6","in":{"base":"ProofRegion","pred":"isinstance(ip.compiled, PCompare) and isinstance(sub, PVar)"},"out":{"base":"bool"},"spec":{"lhs":"_discharge_region_z3(reg)","rhs":"try to discharge a region's obligation via z3","over":{"base":"ProofRegion","pred":"isinstance(ip.compiled, PCompare) and isinstance(sub, PVar)"},"name":"_discharge_region_z3_correct"},"guarantee":"try to discharge a region's obligation via z3","fibers":[{"name":"PCompare","pred":"isinstance(ip.compiled, PCompare)","path":{"lhs":"_discharge_region_z3(x)","rhs":"try to discharge a region's obligation via z3","over":{"base":"PCompare","pred":"isinstance(ip.compiled, PCompare)"},"name":"_discharge_region_z3_PCompare_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_z3_PCompare_correct","statement":"_discharge_region_z3 satisfies spec on PCompare inputs"},"trust":"LIBRARY"},{"name":"PVar","pred":"isinstance(sub, PVar)","path":{"lhs":"_discharge_region_z3(x)","rhs":"try to discharge a region's obligation via z3","over":{"base":"PVar","pred":"isinstance(sub, PVar)"},"name":"_discharge_region_z3_PVar_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_z3_PVar_correct","statement":"_discharge_region_z3 satisfies spec on PVar inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":2,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"068e9f47fcbbbb39"}
def _discharge_region_z3(region: ProofRegion) -> bool:
    """Try to discharge a region's obligation via Z3."""
    if not region.z3_formula:
        return False

    # Build Z3 variables from the predicates
    variables: Dict[str, str] = {}
    for ip in region.entry_invariants + region.exit_invariants:
        if isinstance(ip.compiled, PCompare):
            for sub in [ip.compiled.left, ip.compiled.right]:
                if isinstance(sub, PVar):
                    variables[sub.name] = 'Int'  # default sort

    try:
        proof = Z3Discharge(
            formula=region.z3_formula,
            fragment='qf_lia',
            variables=variables,
        )
        # Verify with the checker
        lhs = OAbstract(region.obligation_text, ())
        rhs = OAbstract('True', ())
        result = check_proof(proof, lhs, rhs)
        if result.valid:
            region.proof = proof
            region.trust = TrustLevel.KERNEL
            return True
    except Exception:
        pass

    return False


