# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_library","kind":"function","src_hash":"2a99338303d16491","in":{"base":"ProofRegion"},"out":{"base":"bool"},"spec":{"lhs":"_discharge_region_library(reg)","rhs":"try to discharge a region using library axioms","over":{"base":"ProofRegion"},"name":"_discharge_region_library_correct"},"guarantee":"try to discharge a region using library axioms","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_library_correct","statement":"Path(_discharge_region_library(x), try to discharge a region using library axioms)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"333ac610c3c7cf1b"}
def _discharge_region_library(region: ProofRegion) -> bool:
    """Try to discharge a region using library axioms."""
    # Check if any invariants reference library facts
    for ip in region.entry_invariants:
        if ip.kind == MarkerKind.LIBRARY_FACT and ip.library:
            try:
                from cctt.proof_theory.library_axioms import (
                    LibraryAxiom, get_library,
                )
                theory = get_library(ip.library)
                if theory:
                    proof = LibraryAxiom(
                        library=ip.library,
                        axiom_name=f'fact_{ip.surface_text[:30]}',
                        statement=ip.surface_text,
                    )
                    region.proof = proof
                    region.trust = TrustLevel.LIBRARY
                    return True
            except ImportError:
                pass

    return False


