# ║ Path(_discharge_region_structural(reg), discharge via structural rules (reflexivity, trivial implications)) over ProofRegion ║
# ╠════════════════════════════════════════════════════════════╣
# ║ _discharge_region_structural : ProofRegion → bool          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   z3.Solver.check                                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | c15cdf2e2a3640fe  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_structural","kind":"function","src_hash":"221942ed8afe63b4","in":{"base":"ProofRegion"},"out":{"base":"bool"},"spec":{"lhs":"_discharge_region_structural(reg)","rhs":"discharge via structural rules (reflexivity, trivial implications)","over":{"base":"ProofRegion"},"name":"_discharge_region_structural_correct"},"guarantee":"discharge via structural rules (reflexivity, trivial implications)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._discharge_region_structural_correct","statement":"Path(_discharge_region_structural(x), discharge via structural rules (reflexivity, trivial implications))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c15cdf2e2a3640fe"}
def _discharge_region_structural(region: ProofRegion) -> bool:
    """Discharge via structural rules (reflexivity, trivial implications)."""
    # If entry and exit invariants are identical, it's reflexivity
    if (region.entry_invariants and region.exit_invariants and
            len(region.entry_invariants) == len(region.exit_invariants)):
        all_same = all(
            e.surface_text == x.surface_text
            for e, x in zip(region.entry_invariants, region.exit_invariants)
        )
        if all_same:
            region.proof = Refl(term=OAbstract(
                region.entry_invariants[0].surface_text, ()))
            region.trust = TrustLevel.KERNEL
            return True

    # If no exit invariants, the region is trivially satisfied
    if not region.exit_invariants:
        region.proof = Refl(term=OAbstract('True', ()))
        region.trust = TrustLevel.KERNEL
        return True

    # If no entry invariants (precondition-free), still a valid proof point
    if not region.entry_invariants and region.exit_invariants:
        # This is really an assumption — the exit invariant is asserted
        proof = Assume(
            label=f'assert_{region.region_id}',
            assumed_lhs=OAbstract(
                region.exit_invariants[0].surface_text, ()),
            assumed_rhs=OAbstract('True', ()),
        )
        region.proof = proof
        region.trust = TrustLevel.ASSUMED
        return True

    return False


