# ║ discharge_region : ProofRegion → bool                      ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   z3.Solver.check                                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | 154bb4a81da27f37  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.discharge_region","kind":"function","src_hash":"125535087d89b09f","in":{"base":"ProofRegion"},"out":{"base":"bool"},"spec":{"lhs":"discharge_region(reg)","rhs":"try all discharge strategies on a region, in order of trust","over":{"base":"ProofRegion"},"name":"discharge_region_correct"},"guarantee":"try all discharge strategies on a region, in order of trust","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.discharge_region_correct","statement":"Path(discharge_region(x), try all discharge strategies on a region, in order of trust)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"154bb4a81da27f37"}
def discharge_region(region: ProofRegion) -> bool:
    """Try all discharge strategies on a region, in order of trust.

    Returns True if the region was discharged (proof assigned).
    """
    if region.is_proved:
        return True

    # Try in order: Z3 → structural → library → assume
    if _discharge_region_z3(region):
        return True
    if _discharge_region_structural(region):
        return True
    if _discharge_region_library(region):
        return True
    if _discharge_region_assume(region):
        return True

    return False


