# ║ Path(discharge_overlap(ove), discharge an overlap obligation) over OverlapObligation ║
# ╠════════════════════════════════════════════════════════════╣
# ║ discharge_overlap : OverlapObligation → bool               ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   z3.Solver.check                                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | eb2191870b854024  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.discharge_overlap","kind":"function","src_hash":"fbabddc13803ed93","in":{"base":"OverlapObligation"},"out":{"base":"bool"},"spec":{"lhs":"discharge_overlap(ove)","rhs":"discharge an overlap obligation","over":{"base":"OverlapObligation"},"name":"discharge_overlap_correct"},"guarantee":"discharge an overlap obligation","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.discharge_overlap_correct","statement":"Path(discharge_overlap(x), discharge an overlap obligation)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"eb2191870b854024"}
def discharge_overlap(overlap: OverlapObligation) -> bool:
    """Discharge an overlap obligation.

    Check that invariants from both branches are compatible at the join.
    """
    # If both branches have the same invariants, compatibility is trivial
    texts_a = {ip.surface_text for ip in overlap.invariants_a}
    texts_b = {ip.surface_text for ip in overlap.invariants_b}

    if texts_a == texts_b:
        overlap.proof = Refl(term=OAbstract('overlap_compat', ()))
        overlap.trust = TrustLevel.KERNEL
        return True

    # If one side is empty, the other is vacuously compatible
    if not overlap.invariants_a or not overlap.invariants_b:
        overlap.proof = Refl(term=OAbstract('vacuous_overlap', ()))
        overlap.trust = TrustLevel.STRUCTURAL
        return True

    # Otherwise, assume compatibility
    overlap.proof = Assume(
        label=f'overlap_{overlap.join_node_id}',
        assumed_lhs=OAbstract(str(texts_a), ()),
        assumed_rhs=OAbstract(str(texts_b), ()),
    )
    overlap.trust = TrustLevel.ASSUMED
    return True


