# ║ Path(compute_h1(cov), compute h¹ of the invariant cover's čech complex) over InvariantCover ║
# ╠════════════════════════════════════════════════════════════╣
# ║ compute_h1 : InvariantCover → int                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
# ║   z3.Solver.check                                          ║
# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | 95580ab594960390  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.compute_h1","kind":"function","src_hash":"edc87e2926e7ba06","in":{"base":"InvariantCover"},"out":{"base":"int"},"spec":{"lhs":"compute_h1(cov)","rhs":"compute h\u00b9 of the invariant cover's \u010dech complex","over":{"base":"InvariantCover"},"name":"compute_h1_correct"},"guarantee":"compute h\u00b9 of the invariant cover's \u010dech complex","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.compute_h1_correct","statement":"Path(compute_h1(x), compute h\u00b9 of the invariant cover's \u010dech complex)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"95580ab594960390"}
def compute_h1(cover: InvariantCover) -> int:
    """Compute H¹ of the invariant cover's Čech complex.

    The complex is:
        C⁰ = ⊕ regions (0-cochains: per-region proofs)
        C¹ = ⊕ overlaps (1-cochains: overlap compatibility)
        δ⁰: C⁰ → C¹ (restriction maps)

    H¹ = ker(δ¹) / im(δ⁰)

    In practice:
    - If all regions are proved and all overlaps are compatible: H¹ = 0
    - Each unproved region or incompatible overlap contributes to H¹
    - H¹ counts the number of independent obstructions to gluing
    """
    # Count unresolved obstructions
    unproved_regions = sum(1 for r in cover.regions if not r.is_proved)
    unresolved_overlaps = sum(1 for o in cover.overlaps
                              if o.proof is None)

    # H¹ is the number of independent obstructions
    # Each unproved region is a direct obstruction (failed to extend section)
    # Each unresolved overlap is a cocycle failure
    cover.h1_rank = unproved_regions + unresolved_overlaps
    return cover.h1_rank


