# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.apply_decomposition","kind":"function","src_hash":"af846378141b164d","in":{"base":"str"},"out":{"base":"str"},"spec":{"lhs":"apply_decomposition(sou)","rhs":"apply an llm decomposition suggestion to source code","over":{"base":"str"},"name":"apply_decomposition_correct"},"guarantee":"apply an llm decomposition suggestion to source code","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.apply_decomposition_correct","statement":"Path(apply_decomposition(x), apply an llm decomposition suggestion to source code)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"475309de5eda3bf2"}
def apply_decomposition(source: str,
                        suggestion: DecompositionSuggestion) -> str:
    """Apply an LLM decomposition suggestion to source code.

    Inserts invariant()/loop_invariant()/library_fact() calls at the
    suggested program points.

    Returns modified source code with markers inserted.
    """
    lines = source.split('\n')
    insertions: List[Tuple[int, str]] = []

    for inv in suggestion.invariants:
        pred = inv.get('predicate', '')
        line_hint = inv.get('line', '')

        # Find the insertion point
        insert_at = _find_insertion_line(lines, line_hint)
        if insert_at >= 0:
            # Detect indentation
            indent = _detect_indent(lines, insert_at)
            insertions.append(
                (insert_at, f'{indent}invariant({pred!r})')
            )

    for li in suggestion.loop_invariants:
        pred = li.get('predicate', '')
        line_hint = li.get('line', '')
        insert_at = _find_insertion_line(lines, line_hint)
        if insert_at >= 0:
            indent = _detect_indent(lines, insert_at)
            insertions.append(
                (insert_at, f'{indent}loop_invariant({pred!r})')
            )

    for lf in suggestion.library_facts:
        lib = lf.get('library', '')
        fact = lf.get('fact', '')
        line_hint = lf.get('line', '0')
        insert_at = _find_insertion_line(lines, line_hint)
        if insert_at >= 0:
            indent = _detect_indent(lines, insert_at)
            insertions.append(
                (insert_at, f'{indent}library_fact({lib!r}, {fact!r})')
            )

    # Sort insertions by line number (descending) to preserve positions
    insertions.sort(key=lambda x: x[0], reverse=True)
    for line_no, text in insertions:
        lines.insert(line_no, text)

    return '\n'.join(lines)


