# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._find_insertion_line","kind":"function","src_hash":"64522f05bf0b4721","in":{"base":"List[str]","pred":"isinstance(hint, str)"},"out":{"base":"int"},"spec":{"lhs":"_find_insertion_line(lin)","rhs":"find the line number to insert at, given a hint","over":{"base":"List[str]","pred":"isinstance(hint, str)"},"name":"_find_insertion_line_correct"},"guarantee":"find the line number to insert at, given a hint","fibers":[{"name":"str","pred":"isinstance(hint, str)","path":{"lhs":"_find_insertion_line(x)","rhs":"find the line number to insert at, given a hint","over":{"base":"str","pred":"isinstance(hint, str)"},"name":"_find_insertion_line_str_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._find_insertion_line_str_correct","statement":"_find_insertion_line satisfies spec on str inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"1f8c626a3fe41ec8"}
def _find_insertion_line(lines: List[str], hint: str) -> int:
    """Find the line number to insert at, given a hint."""
    # Try as integer line number
    try:
        n = int(hint)
        return max(0, min(n, len(lines)))
    except (ValueError, TypeError):
        pass

    # Try as substring match
    if isinstance(hint, str) and hint:
        for i, line in enumerate(lines):
            if hint in line:
                return i + 1  # insert after the matching line
    return -1


