# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._detect_indent","kind":"function","src_hash":"a5dcc551bee1470d","in":{"base":"List[str]"},"out":{"base":"str"},"spec":{"lhs":"_detect_indent(lin)","rhs":"detect the indentation level at the given line","over":{"base":"List[str]"},"name":"_detect_indent_correct","kind":"composition"},"guarantee":"detect the indentation level at the given line","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"len","by":"library_axiom"},{"fn":"len","by":"library_axiom"},{"fn":"lstrip","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"fc95fabfde0ec3a6"}
def _detect_indent(lines: List[str], line_no: int) -> str:
    """Detect the indentation level at the given line."""
    if 0 <= line_no < len(lines):
        line = lines[line_no]
        return line[:len(line) - len(line.lstrip())]
    # Find the nearest non-empty line
    for offset in [0, -1, 1, -2, 2]:
        idx = line_no + offset
        if 0 <= idx < len(lines) and lines[idx].strip():
            line = lines[idx]
            return line[:len(line) - len(line.lstrip())]
    return '    '


