# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.decompose","kind":"function","src_hash":"18a959ce6f6800d2","in":{"base":"Callable"},"out":{"base":"Callable"},"spec":{"lhs":"decompose(fun)","rhs":"decorator: decompose a function via its invariant markers and prove","over":{"base":"Callable"},"name":"decompose_correct"},"guarantee":"decorator: decompose a function via its invariant markers and prove","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.decompose_correct","statement":"Path(decompose(x), decorator: decompose a function via its invariant markers and prove)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ad6cbb7054abd3ff"}
def decompose(func: Callable) -> Callable:
    """Decorator: decompose a function via its invariant markers and prove.

    Extracts invariant markers from the function body, builds a CFG,
    generates verification conditions, and attempts to prove each region.

    Attaches the InvariantCover as metadata on the function.

    Usage::

        @decompose
        @postcondition("result >= 0")
        def abs_val(x: int) -> int:
            precondition("isinstance(x, int)")
            if x < 0:
                return -x
            return x
    """
    try:
        source = textwrap.dedent(inspect.getsource(func))
    except (OSError, TypeError):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)
        wrapper.__cover__ = None
        return wrapper

    # Get postconditions from decorator metadata
    guarantee = ''
    postconds = getattr(func, '__postconditions__', [])
    if postconds:
        guarantee = ' and '.join(postconds)

    cover = decompose_and_prove(source, guarantee)

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)

    wrapper.__cover__ = cover
    wrapper.__trust__ = cover.trust
    wrapper.__h1__ = cover.h1_rank
    wrapper.__globally_proved__ = cover.is_globally_proved
    return wrapper


