# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.decompose_library_function","kind":"function","src_hash":"2b667754c7dac3fa","in":{"base":"str"},"out":{"base":"InvariantCover"},"spec":{"lhs":"decompose_library_function(sou)","rhs":"decompose and prove a library function (for use by library_prover)","over":{"base":"str"},"name":"decompose_library_function_correct"},"guarantee":"decompose and prove a library function (for use by library_prover)","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.decompose_library_function_correct","statement":"Path(decompose_library_function(x), decompose and prove a library function (for use by library_prover))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"0380119ab59b50bc"}
def decompose_library_function(source: str,
                               func_name: str,
                               library: str = '',
                               guarantee: str = '') -> InvariantCover:
    """Decompose and prove a library function (for use by library_prover).

    This is the integration point between cohomological_decomposition
    and library_prover. It:
    1. Auto-inserts a precondition from library contracts
    2. Runs the full pipeline
    3. Returns the cover for inclusion in the library proof report

    If the function has no explicit markers, creates a minimal cover
    with just the library contract as axiom.
    """
    # If we have a library, look up the contract
    if library:
        try:
            from cctt.proof_theory.library_axioms import get_library
            theory = get_library(library)
            if theory:
                contract = theory.get_contract(func_name)
                if contract:
                    # Add library preconditions as markers
                    for pre_name, pre_text in contract.preconditions.items():
                        source = _insert_after_def(
                            source,
                            f'    precondition({pre_text!r})')
                    if contract.postcondition:
                        guarantee = guarantee or contract.postcondition
        except ImportError:
            pass

    cover = decompose_and_prove(source, guarantee)
    return cover


