# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._insert_after_def","kind":"function","src_hash":"3f5054c8f636f9b4","in":{"base":"str"},"out":{"base":"str"},"spec":{"lhs":"_insert_after_def(sou)","rhs":"insert a line right after the function's def line","over":{"base":"str"},"name":"_insert_after_def_correct"},"guarantee":"insert a line right after the function's def line","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._insert_after_def_correct","statement":"Path(_insert_after_def(x), insert a line right after the function's def line)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8e6f714bcb13212b"}
def _insert_after_def(source: str, line_to_insert: str) -> str:
    """Insert a line right after the function's def line."""
    lines = source.split('\n')
    for i, line in enumerate(lines):
        stripped = line.lstrip()
        if stripped.startswith('def '):
            # Skip docstring if present
            next_i = i + 1
            if next_i < len(lines):
                next_line = lines[next_i].lstrip()
                if next_line.startswith(('"""', "'''")):
                    # Find end of docstring
                    quote = next_line[:3]
                    if next_line.count(quote) >= 2:
                        next_i += 1
                    else:
                        for j in range(next_i + 1, len(lines)):
                            if quote in lines[j]:
                                next_i = j + 1
                                break
                lines.insert(next_i, line_to_insert)
                return '\n'.join(lines)
    return source


