# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition._heuristic_refinement","kind":"function","src_hash":"f8e8c7cb079abf03","in":{"base":"str"},"out":{"base":"Optional[DecompositionSuggestion]"},"spec":{"lhs":"_heuristic_refinement(sou)","rhs":"simple heuristic refinement when no llm is available","over":{"base":"str"},"name":"_heuristic_refinement_correct"},"guarantee":"simple heuristic refinement when no llm is available","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition._heuristic_refinement_correct","statement":"Path(_heuristic_refinement(x), simple heuristic refinement when no llm is available)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"4a42f25bc6e3eb2a"}
def _heuristic_refinement(source: str,
                          cover: InvariantCover,
                          feedback: DecompositionFeedback,
                          ) -> Optional[DecompositionSuggestion]:
    """Simple heuristic refinement when no LLM is available.

    Adds obvious invariants:
    - Type assertions at function entry
    - len() invariants after list operations
    - Value range checks after arithmetic
    """
    invariants = []

    # For failed regions, try to add intermediate invariants
    for fr in feedback.failed_regions:
        # If the region spans multiple statements, suggest splitting
        if 'large' in fr.get('reason', '').lower() or not fr.get('reason'):
            invariants.append({
                'line': fr.get('region', '0'),
                'predicate': 'True',  # trivial invariant to split region
            })

    if invariants:
        return DecompositionSuggestion(
            invariants=invariants,
            loop_invariants=[],
            library_facts=[],
            reasoning='heuristic: added trivial invariants to split large regions',
        )

    return None


