# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.cohomological_decomposition.verify_annotations","kind":"function","src_hash":"1eebaf95aa5e4d1b","in":{"base":"str"},"out":{"base":"Dict[str, Any]"},"spec":{"lhs":"verify_annotations(sou)","rhs":"verify all invariant annotations in a source file","over":{"base":"str"},"name":"verify_annotations_correct"},"guarantee":"verify all invariant annotations in a source file","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.cohomological_decomposition.verify_annotations_correct","statement":"Path(verify_annotations(x), verify all invariant annotations in a source file)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"444e694e3ed5811a"}
def verify_annotations(source: str) -> Dict[str, Any]:
    """Verify all invariant annotations in a source file.

    Parses all marker calls, checks they can be compiled to formal
    predicates, and reports any issues.
    """
    markers = extract_markers(source)

    results = {
        'total': len(markers),
        'formal': sum(1 for m in markers if m.is_formal),
        'fallback': sum(1 for m in markers if m.parse_status == 'fallback'),
        'failed': sum(1 for m in markers if m.parse_status == 'failed'),
        'by_kind': {},
        'issues': [],
    }

    for kind in MarkerKind:
        count = sum(1 for m in markers if m.kind == kind)
        if count:
            results['by_kind'][kind.value] = count

    for m in markers:
        if m.parse_status != 'ok':
            results['issues'].append({
                'line': m.line,
                'kind': m.kind.value,
                'text': m.surface_text,
                'status': m.parse_status,
            })

    return results
